    private void btnRegistrarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnRegistrarActionPerformed
    if (txtQuantidade.getText().isEmpty()) {
        JOptionPane.showMessageDialog(null, "Digite a quantidade!");
        return;
    }

    try {
        String tipo = cbTipo.getSelectedItem().toString();
        int quantidade = Integer.parseInt(txtQuantidade.getText());

        Connection conn = (Connection) Conexao.conectar();

        String sql = "INSERT INTO movimentacao (tipo, quantidade) VALUES (?, ?)";

        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, tipo);
        stmt.setInt(2, quantidade);

        stmt.execute();

        JOptionPane.showMessageDialog(null, "Movimentaçăo registrada com sucesso!");

        // Limpar campo
        txtQuantidade.setText("");

    } catch (Exception e) {
        JOptionPane.showMessageDialog(null, "Erro: " + e);
   }  
    }//GEN-LAST:event_btnRegistrarActionPerformed

